-- PASSO 0: Inserir campanha do monitoramento
SELECT 'C028-2026-05-SC'
WHERE NOT EXISTS (SELECT 1 FROM campanhas WHERE nome_campanha = 'C028-2026-05-SC');

-- PASSO 1: Inserir especies novas
ON CONFLICT (nome_cientifico) DO NOTHING;

-- PASSO 1.5: Limpeza controlada para reexecucao da carga de ictio
WITH pontos_alvo AS (
  SELECT pc.id_ponto_coleta
  FROM pontos_coleta pc
  JOIN campanhas c ON c.id_campanha = pc.id_campanha
  WHERE pc.id_projeto = 165
    AND c.nome_campanha = 'C028-2026-05-SC'
    AND pc.nome_ponto IN ('RPDGN0', 'RPDGN1', 'RPDGN2', 'RPDGN3', 'RPFOR1', 'RPFOR2', 'RPFOR3', 'RPJAC1', 'RPJAC2', 'RPJAC3', 'RPJAC4', 'RPJAC5', 'RPSPT1', 'RPSPT2', 'RPSPT3', 'RPSPT4', 'RPSPT5', 'TRDGN1', 'TRDGN2', 'TRDGN3', 'TRFOR1', 'TRFOR2', 'TRFOR3', 'TRFOR4', 'TRFOR5', 'TRJAC1', 'TRJAC2', 'TRJAC3', 'TRJAC4', 'TRSPT1', 'TRSPT2', 'TRSPT3')
)
DELETE FROM resultados_ictiofauna ri
WHERE ri.id_esforco IN (
  SELECT ea.id_esforco
  FROM esforcos_amostragem ea
  WHERE ea.grupo_biologico = 'Ictiofauna'
    AND ea.id_ponto_coleta IN (SELECT id_ponto_coleta FROM pontos_alvo)
);
WITH pontos_alvo AS (
  SELECT pc.id_ponto_coleta
  FROM pontos_coleta pc
  JOIN campanhas c ON c.id_campanha = pc.id_campanha
  WHERE pc.id_projeto = 165
    AND c.nome_campanha = 'C028-2026-05-SC'
    AND pc.nome_ponto IN ('RPDGN0', 'RPDGN1', 'RPDGN2', 'RPDGN3', 'RPFOR1', 'RPFOR2', 'RPFOR3', 'RPJAC1', 'RPJAC2', 'RPJAC3', 'RPJAC4', 'RPJAC5', 'RPSPT1', 'RPSPT2', 'RPSPT3', 'RPSPT4', 'RPSPT5', 'TRDGN1', 'TRDGN2', 'TRDGN3', 'TRFOR1', 'TRFOR2', 'TRFOR3', 'TRFOR4', 'TRFOR5', 'TRJAC1', 'TRJAC2', 'TRJAC3', 'TRJAC4', 'TRSPT1', 'TRSPT2', 'TRSPT3')
)
DELETE FROM esforcos_amostragem ea
WHERE ea.grupo_biologico = 'Ictiofauna'
  AND ea.id_ponto_coleta IN (SELECT id_ponto_coleta FROM pontos_alvo);
WITH pontos_alvo AS (
  SELECT pc.id_ponto_coleta
  FROM pontos_coleta pc
  JOIN campanhas c ON c.id_campanha = pc.id_campanha
  WHERE pc.id_projeto = 165
    AND c.nome_campanha = 'C028-2026-05-SC'
    AND pc.nome_ponto IN ('RPDGN0', 'RPDGN1', 'RPDGN2', 'RPDGN3', 'RPFOR1', 'RPFOR2', 'RPFOR3', 'RPJAC1', 'RPJAC2', 'RPJAC3', 'RPJAC4', 'RPJAC5', 'RPSPT1', 'RPSPT2', 'RPSPT3', 'RPSPT4', 'RPSPT5', 'TRDGN1', 'TRDGN2', 'TRDGN3', 'TRFOR1', 'TRFOR2', 'TRFOR3', 'TRFOR4', 'TRFOR5', 'TRJAC1', 'TRJAC2', 'TRJAC3', 'TRJAC4', 'TRSPT1', 'TRSPT2', 'TRSPT3')
)
DELETE FROM pontos_coleta pc
WHERE pc.id_ponto_coleta IN (SELECT id_ponto_coleta FROM pontos_alvo)
  AND NOT EXISTS (
    SELECT 1 FROM esforcos_amostragem ea WHERE ea.id_ponto_coleta = pc.id_ponto_coleta
  );

-- PASSO 2: Inserir pontos da campanha C028-2026-05-SC
