-- PASSO 4: Inserir resultados ictiofauna validos (linhas sem especie foram tratadas como ausencia de captura e permanecem apenas no esforco)
;

-- VALIDACAO POS-MIGRACAO
SELECT COUNT(*) AS n_pontos FROM pontos_coleta pc JOIN campanhas c ON c.id_campanha = pc.id_campanha WHERE pc.id_projeto = 165 AND c.nome_campanha = 'C028-2026-05-SC';
SELECT COUNT(*) AS n_esforcos FROM esforcos_amostragem ea JOIN pontos_coleta pc ON pc.id_ponto_coleta = ea.id_ponto_coleta JOIN campanhas c ON c.id_campanha = pc.id_campanha WHERE pc.id_projeto = 165 AND c.nome_campanha = 'C028-2026-05-SC' AND ea.grupo_biologico = 'Ictiofauna';
SELECT COUNT(*) AS n_resultados FROM resultados_ictiofauna ri JOIN esforcos_amostragem ea ON ea.id_esforco = ri.id_esforco JOIN pontos_coleta pc ON pc.id_ponto_coleta = ea.id_ponto_coleta JOIN campanhas c ON c.id_campanha = pc.id_campanha WHERE pc.id_projeto = 165 AND c.nome_campanha = 'C028-2026-05-SC';
SELECT COUNT(DISTINCT e.nome_cientifico) AS n_especies FROM resultados_ictiofauna ri JOIN esforcos_amostragem ea ON ea.id_esforco = ri.id_esforco JOIN pontos_coleta pc ON pc.id_ponto_coleta = ea.id_ponto_coleta JOIN campanhas c ON c.id_campanha = pc.id_campanha JOIN especies e ON e.id_especie = ri.id_especie WHERE pc.id_projeto = 165 AND c.nome_campanha = 'C028-2026-05-SC';